UPDATE J09C_temp
SET ENTSCHEIDUNG = (
  SELECT CASE WHEN COUNT(DISTINCT EQUNR) < 3 THEN 'KSA' ELSE 'EVU' END
  FROM J09C_temp t2
  WHERE t2.HAUS = J09C_temp.HAUS
);

UPDATE J09C_temp SET ENTSCHEIDUNG = 'EVU'
WHERE CITY1 IN ('Wiblingwerde', 'Breckerfeld')
   OR CITY2 IN ('Wiblingwerde', 'Breckerfeld');
